@* Displays a single task with title, assignee, priority badge, due date, and move buttons *@

<div class="card mb-2">
    <div class="card-body p-2">
        <h6 class="card-title mb-1">@Task.Title</h6>
        <p class="card-text mb-1 text-muted small">@Task.Assignee</p>
        <div class="d-flex justify-content-between align-items-center mb-1">
            <span class="badge @PriorityClass">@Task.Priority</span>
            <small class="text-muted">@Task.DueDate.ToString("MMM dd")</small>
        </div>
        <div class="d-flex justify-content-between">
            @if (CanMoveLeft)
            {
                <button class="btn btn-outline-secondary btn-sm" @onclick="OnMoveLeftClick">&larr; Move Left</button>
            }
            else
            {
                <span></span>
            }
            @if (CanMoveRight)
            {
                <button class="btn btn-outline-secondary btn-sm" @onclick="OnMoveRightClick">Move Right &rarr;</button>
            }
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public TaskItem Task { get; set; } = default!;
    [Parameter] public bool CanMoveLeft { get; set; }
    [Parameter] public bool CanMoveRight { get; set; }
    [Parameter] public EventCallback OnMoveLeftClick { get; set; }
    [Parameter] public EventCallback OnMoveRightClick { get; set; }

    private string PriorityClass => Task.Priority switch
    {
        "High" => "bg-danger",
        "Medium" => "bg-warning text-dark",
        "Low" => "bg-success",
        _ => "bg-secondary"
    };
}

@* Inline form for creating a new task within a column *@

<div class="card mb-2 border-primary">
    <div class="card-body p-2">
        <div class="mb-2">
            <input type="text" class="form-control form-control-sm" placeholder="Title" @bind="title" />
        </div>
        <div class="mb-2">
            <input type="text" class="form-control form-control-sm" placeholder="Assignee" @bind="assignee" />
        </div>
        <div class="mb-2">
            <select class="form-select form-select-sm" @bind="priority">
                <option value="High">High</option>
                <option value="Medium">Medium</option>
                <option value="Low">Low</option>
            </select>
        </div>
        <div class="mb-2">
            <input type="date" class="form-control form-control-sm" @bind="dueDate" />
        </div>
        <div class="d-flex gap-2">
            <button class="btn btn-primary btn-sm" @onclick="HandleSave" disabled="@saving">
                @(saving ? "Saving..." : "Save")
            </button>
            <button class="btn btn-outline-secondary btn-sm" @onclick="HandleCancel" disabled="@saving">Cancel</button>
        </div>
    </div>
</div>

@code {
    [Parameter] public EventCallback<TaskItem> OnTaskCreated { get; set; }
    [Parameter] public EventCallback OnCancel { get; set; }
    [Parameter, EditorRequired] public string DefaultStatus { get; set; } = "";
    [Parameter, EditorRequired] public ITaskService TaskService { get; set; } = default!;

    private string title = "";
    private string assignee = "";
    private string priority = "Medium";
    private DateTime dueDate = DateTime.Today.AddDays(7);
    private bool saving;

    private async Task HandleSave()
    {
        if (string.IsNullOrWhiteSpace(title)) return;

        saving = true;
        try
        {
            var created = await TaskService.CreateTaskAsync(title, assignee, priority, dueDate);
            await OnTaskCreated.InvokeAsync(created);
        }
        finally
        {
            saving = false;
        }
    }

    private async Task HandleCancel()
    {
        await OnCancel.InvokeAsync();
    }
}

@* Summary stats bar: total tasks, per-column counts, overdue count *@

<div class="d-flex gap-3 flex-wrap mb-3 p-2 bg-light rounded">
    <span class="badge bg-primary fs-6">Total: @Tasks.Count</span>
    <span class="badge bg-secondary fs-6">To Do: @Tasks.Count(t => t.Status == "To Do")</span>
    <span class="badge bg-info text-dark fs-6">In Progress: @Tasks.Count(t => t.Status == "In Progress")</span>
    <span class="badge bg-success fs-6">Done: @Tasks.Count(t => t.Status == "Done")</span>
    <span class="badge bg-danger fs-6">Overdue: @Tasks.Count(t => t.DueDate < DateTime.Today)</span>
</div>

@code {
    [Parameter, EditorRequired] public List<TaskItem> Tasks { get; set; } = new();
}

@* Search bar for filtering tasks by title *@

<div class="mb-3">
    <input type="text"
           class="form-control"
           placeholder="Search tasks by title..."
           value="@SearchText"
           @oninput="HandleInput" />
</div>

@code {
    [Parameter] public string SearchText { get; set; } = "";
    [Parameter] public EventCallback<string> OnSearchChanged { get; set; }

    private async Task HandleInput(ChangeEventArgs e)
    {
        await OnSearchChanged.InvokeAsync(e.Value?.ToString() ?? "");
    }
}

@* A single Kanban column: header with count, task cards, and add-task button/form *@

<div class="col">
    <div class="card h-100">
        <div class="card-header d-flex justify-content-between align-items-center">
            <h5 class="mb-0">@ColumnName</h5>
            <span class="badge bg-secondary">@Tasks.Count</span>
        </div>
        <div class="card-body p-2" style="min-height: 200px; overflow-y: auto;">
            @foreach (var task in Tasks)
            {
                <TaskCard Task="task"
                          CanMoveLeft="CanMoveLeft"
                          CanMoveRight="CanMoveRight"
                          OnMoveLeftClick="() => HandleMoveLeft(task)"
                          OnMoveRightClick="() => HandleMoveRight(task)" />
            }

            @if (showForm)
            {
                <AddTaskForm DefaultStatus="@ColumnName"
                             TaskService="TaskService"
                             OnTaskCreated="HandleTaskCreated"
                             OnCancel="() => showForm = false" />
            }
        </div>
        <div class="card-footer">
            <button class="btn btn-outline-primary btn-sm w-100" @onclick="() => showForm = true" disabled="@showForm">
                + Add Task
            </button>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public string ColumnName { get; set; } = "";
    [Parameter, EditorRequired] public List<TaskItem> Tasks { get; set; } = new();
    [Parameter] public bool CanMoveLeft { get; set; }
    [Parameter] public bool CanMoveRight { get; set; }
    [Parameter, EditorRequired] public string? LeftColumnName { get; set; }
    [Parameter, EditorRequired] public string? RightColumnName { get; set; }
    [Parameter] public EventCallback<(int TaskId, string NewStatus)> OnMoveTask { get; set; }
    [Parameter] public EventCallback<TaskItem> OnTaskCreated { get; set; }
    [Parameter, EditorRequired] public ITaskService TaskService { get; set; } = default!;

    private bool showForm;

    private async Task HandleMoveLeft(TaskItem task)
    {
        if (LeftColumnName is not null)
            await OnMoveTask.InvokeAsync((task.Id, LeftColumnName));
    }

    private async Task HandleMoveRight(TaskItem task)
    {
        if (RightColumnName is not null)
            await OnMoveTask.InvokeAsync((task.Id, RightColumnName));
    }

    private async Task HandleTaskCreated(TaskItem task)
    {
        showForm = false;
        await OnTaskCreated.InvokeAsync(task);
    }
}

@page "/board"
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h3 class="mb-3">Project Board</h3>

@if (loading)
{
    <div class="d-flex justify-content-center my-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
    </div>
}
else if (errorMessage is not null)
{
    <div class="alert alert-danger" role="alert">
        <strong>Error loading tasks:</strong> @errorMessage
        <button class="btn btn-outline-danger btn-sm ms-3" @onclick="LoadTasks">Retry</button>
    </div>
}
else
{
    <BoardStatsBar Tasks="allTasks" />
    <BoardSearchBar SearchText="@searchText" OnSearchChanged="HandleSearchChanged" />

    <div class="row g-3">
        @foreach (var col in columns)
        {
            var colTasks = FilteredTasks.Where(t => t.Status == col.Name).ToList();
            <BoardColumn ColumnName="@col.Name"
                         Tasks="colTasks"
                         CanMoveLeft="col.LeftName is not null"
                         CanMoveRight="col.RightName is not null"
                         LeftColumnName="@col.LeftName"
                         RightColumnName="@col.RightName"
                         TaskService="TaskService"
                         OnMoveTask="HandleMoveTask"
                         OnTaskCreated="HandleTaskCreated" />
        }
    </div>
}

@code {
    private List<TaskItem> allTasks = new();
    private string searchText = "";
    private bool loading = true;
    private string? errorMessage;

    private record ColumnDef(string Name, string? LeftName, string? RightName);

    private static readonly ColumnDef[] columns =
    {
        new("To Do",        null,          "In Progress"),
        new("In Progress",  "To Do",       "Done"),
        new("Done",         "In Progress", null)
    };

    private IEnumerable<TaskItem> FilteredTasks =>
        string.IsNullOrWhiteSpace(searchText)
            ? allTasks
            : allTasks.Where(t => t.Title.Contains(searchText, StringComparison.OrdinalIgnoreCase));

    protected override async Task OnInitializedAsync()
    {
        await LoadTasks();
    }

    private async Task LoadTasks()
    {
        loading = true;
        errorMessage = null;

        try
        {
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            loading = false;
        }
    }

    private void HandleSearchChanged(string text)
    {
        searchText = text;
    }

    private async Task HandleMoveTask((int TaskId, string NewStatus) move)
    {
        await TaskService.UpdateTaskStatusAsync(move.TaskId, move.NewStatus);

        var idx = allTasks.FindIndex(t => t.Id == move.TaskId);
        if (idx >= 0)
        {
            allTasks[idx] = allTasks[idx] with { Status = move.NewStatus };
        }
    }

    private void HandleTaskCreated(TaskItem task)
    {
        allTasks.Add(task);
    }
}

