{"path": "/tmp/sv-62b933b9589649979cd21d26a65b9701/Components/Pages/Board/BoardColumn.razor", "file_text": "@* A single Kanban column: header with count, task cards, and add-task button/form *@

<div class="col">
    <div class="card h-100">
        <div class="card-header d-flex justify-content-between align-items-center">
            <h5 class="mb-0">@ColumnName</h5>
            <span class="badge bg-secondary">@Tasks.Count</span>
        </div>
        <div class="card-body p-2" style="min-height: 200px; overflow-y: auto;">
            @foreach (var task in Tasks)
            {
                <TaskCard Task="task"
                          CanMoveLeft="CanMoveLeft"
                          CanMoveRight="CanMoveRight"
                          OnMoveLeftClick="() => HandleMoveLeft(task)"
                          OnMoveRightClick="() => HandleMoveRight(task)" />
            }

            @if (showForm)
            {
                <AddTaskForm DefaultStatus="@ColumnName"
                             TaskService="TaskService"
                             OnTaskCreated="HandleTaskCreated"
                             OnCancel="() => showForm = false" />
            }
        </div>
        <div class="card-footer">
            <button class="btn btn-outline-primary btn-sm w-100" @onclick="() => showForm = true" disabled="@showForm">
                + Add Task
            </button>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public string ColumnName { get; set; } = "";
    [Parameter, EditorRequired] public List<TaskItem> Tasks { get; set; } = new();
    [Parameter] public bool CanMoveLeft { get; set; }
    [Parameter] public bool CanMoveRight { get; set; }
    [Parameter, EditorRequired] public string? LeftColumnName { get; set; }
    [Parameter, EditorRequired] public string? RightColumnName { get; set; }
    [Parameter] public EventCallback<(int TaskId, string NewStatus)> OnMoveTask { get; set; }
    [Parameter] public EventCallback<TaskItem> OnTaskCreated { get; set; }
    [Parameter, EditorRequired] public ITaskService TaskService { get; set; } = default!;

    private bool showForm;

    private async Task HandleMoveLeft(TaskItem task)
    {
        if (LeftColumnName is not null)
            await OnMoveTask.InvokeAsync((task.Id, LeftColumnName));
    }

    private async Task HandleMoveRight(TaskItem task)
    {
        if (RightColumnName is not null)
            await OnMoveTask.InvokeAsync((task.Id, RightColumnName));
    }

    private async Task HandleTaskCreated(TaskItem task)
    {
        showForm = false;
        await OnTaskCreated.InvokeAsync(task);
    }
}
"}

